As an AI text model, I cannot directly generate or render a 3D image file (like a .obj, .fbx, or .glb file) that you can download.

However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a powerful JavaScript library for 3D graphics in the browser.

Below is a single-file solution. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser to see the 3D model.

### 3D House Renderer (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 15, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Environment (Ground)
        const groundGeometry = new THREE.PlaneGeometry(200, 200);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction Helper
        function createHouse() {
            const houseGroup = new THREE.Group();

            // Materials
            const wallMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
            const roofMat = new THREE.MeshStandardMaterial({ color: 0x800000 }); // Dark Red
            const windowMat = new THREE.MeshStandardMaterial({ color: 0xADD8E6, emissive: 0x000000 });
            const doorMat = new THREE.MeshStandardMaterial({ color: 0x333333 });

            // Base Dimensions
            const width = 10;
            const depth = 10;
            const height = 6;

            // --- Walls ---
            const wallGeo = new THREE.BoxGeometry(width, height, depth);
            const wall = new THREE.Mesh(wallGeo, wallMat);
            wall.position.y = height / 2;
            wall.castShadow = true;
            wall.receiveShadow = true;
            houseGroup.add(wall);

            // --- Roof ---
            const roofGeo = new THREE.ConeGeometry(width * 1.2, 4, 4);
            const roof = new THREE.Mesh(roofGeo, roofMat);
            roof.position.y = height + 2;
            roof.rotation.y = Math.PI / 4; // Rotate to align with walls
            roof.castShadow = true;
            houseGroup.add(roof);

            // --- Windows (Simple Geometry) ---
            const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);

            // Front Windows
            const win1 = new THREE.Mesh(windowGeo, windowMat);
            win1.position.set(-2, 3, 5);
            houseGroup.add(win1);

            const win2 = new THREE.Mesh(windowGeo, windowMat);
            win2.position.set(2, 3, 5);
            houseGroup.add(win2);

            // Side Windows
            const win3 = new THREE.Mesh(windowGeo, windowMat);
            win3.position.set(5, 3, -2);
            houseGroup.add(win3);

            // --- Door ---
            const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
            const door = new THREE.Mesh(doorGeo, doorMat);
            door.position.set(0, 1.5, 5);
            houseGroup.add(door);

            return houseGroup;
        }

        const house = createHouse();
        scene.add(house);

        // 5. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.maxPolarAngle = Math.PI / 2 - 0.1; // Prevent going under ground

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy the code** above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  **Double-click** `house.html` to open it in your web browser (Chrome, Firefox, Edge, etc.).

### What this code does:
*   **Scene Setup:** Initializes a 3D scene with a sky-blue background and fog for depth.
*   **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts realistic shadows.
*   **Geometry:** Constructs a house using basic geometric primitives:
    *   **Walls:** A `BoxGeometry`.
    *   **Roof:** A `ConeGeometry` rotated to sit on top of the walls.
    *   **Details:** Adds windows and a door using smaller boxes.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.

### Next Steps for Advanced Rendering
If you need a production-ready 3D model (e.g., for a game or architectural visualization), you would typically:
1.  Use a **3D Modeling Software** like Blender, Maya, or SketchUp to design the house.
2.  Export the model as a `.glb` or `.gltf` file.
3.  Load that file into a Three.js application using the `GLTFLoader` module.
